var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 제5 격납고","JPN":"ロータス、第5格納庫","ENG":"Lotus, Hangar 5","TWN":"洛德斯，第5機庫","DEU":"Lotus, Hangar 5","FRA":"Lotus, Hangar 5"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 3.8","JPN":"CSE Lv.3.8","ENG":"CSE Lv. 3.8","TWN":"CSE Lv. 3.8","DEU":"CSE Lv. 3.8","FRA":"CSE Lv. 3.8"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"괜찮겠습니까?","JPN":"大丈夫ですか？","ENG":"Are you sure about this?","TWN":"這樣真的沒問題嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으, 응? 저 사람들을 여기로 불러들이는 것 말이야?","JPN":"う、うん？　あの人たちをここに呼ぶのが？","ENG":"H-huh? You mean inviting those people here?","TWN":"呃，嗯？你說把那些人叫到這裡嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"괜찮지… 않을까?","JPN":"大丈夫……だと思う。","ENG":"It should be fine... I think?","TWN":"應該……沒問題吧？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"일단은 공인 카운터인 네가 있잖아.","JPN":"一応公認カウンターのファティマがいるじゃない。","ENG":"For starters, you are an Official Counter.","TWN":"反正這裡還有你這個公認的制裁者。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아뇨, 그런 걸 걱정하는 게 아닙니다.","JPN":"いいえ、そっちの心配ではありません。","ENG":"No, that is not what I am worried about.","TWN":"不，這點你不用擔心。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"낯을 많이 가리는 시니어님께서 제대로 된 사회적 커뮤니케이션이 가능할지 걱정입니다.","JPN":"人見知りのシニア様が、ちゃんとした社会的コミュニケーションが取れるかが心配なのです。","ENG":"I am worried whether you, who are extremely shy, can handle proper social communication.","TWN":"我擔心平時很怕生的Senior者，是否能正常進行交流。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지난번처럼 말 한마디 못 하고 대화형 인공지능으로 소통하신다던가…….","JPN":"この前のように一言も喋れず、会話型人工知能で疎通をするのは……","ENG":"Like last time, when you could not say a single word and tried to talk through a conversational AI...","TWN":"會不會像上次一樣一句話都說不出口，只靠對話型人工智慧交流之類的……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야! 내, 내가 언제 그렇게까지 했어?!","JPN":"ちょっと！　そ、そこまでしてないよ！","ENG":"Hey! W-when did I ever go that far?!","TWN":" 喂！我、我什麼時候那麼誇張了？！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그냥 몸이 좀 안 좋으니까 대신 말 좀 해달라고 한 거지!","JPN":"ちょっと具合が悪かったから、代わりに話してってお願いしただけ！","ENG":"I just wasn't feeling well, so I asked it to talk for me.","TWN":"我只是因為身體有點不舒服，才會找人代替我說話！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"몇 번이나 남 눈을 쳐다보는 걸 망설이다가 결국은 개인 작업실로 도망치면서까지 말입니까?","JPN":"何度も人と目を合わせるのをためらい、最後には個人作業室に逃げ込んでまでですか？","ENG":"You hesitated to make eye contact so many times, then ran to your private workshop in the end.","TWN":"您是說您看著別人猶豫了好幾次，最後逃回私人工作室後才說話嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님의 큰 뜻을 알아차리지 못해서 유감이군요.","JPN":"なるほど。シニア様の意図を察せず、大変申し訳ありませんでした。","ENG":"My apologies for failing to grasp your grand intent.","TWN":"我沒察覺Senior者的用意真是太可惜了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"씨이…….","JPN":"ちっ……","ENG":"Grr...","TWN":"哼……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"자기 목숨 달린 일이라면 어떻게든 회피하려고 하시는 시니어님이 왜 이번 부탁을 흔쾌히 승낙했는지 궁금하군요.","JPN":"自分の命がかかっていることになると、どんな手を使ってでも逃げようとするシニア様が、今回はなぜ要請にすんなり応じたのですか？","ENG":"You usually shy away when your life’s on the line. So why accept this request so easily?","TWN":"明明只要關係到自己性命的事都會想盡辦法逃避，我真好奇為什麼Senior這次會欣然答應。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……별거 아니야.","JPN":"……大した理由はないよ。","ENG":"...It's nothing special.","TWN":"……沒什麼。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 로터스의 시니어인가?","JPN":"お前がロータスのシニアか？","ENG":"You are Lotus's Senior?","TWN":"你是洛德斯的Senior嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래. 내가 로터스의 시니어, 이졸데야.","JPN":"そう。私がロータスのシニア、イゾルデだよ。","ENG":"Yes. I am Isolde, Senior of Lotus.","TWN":"沒錯，我是洛德斯的Senior，伊索德。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"꼬마 아가씨 이름은 뭐야?","JPN":"お嬢ちゃん、名前はなんて言うの？","ENG":"What is your name?","TWN":"妳叫什麼名字？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미래에 세상을 바꿀 공학자의 이름 정도는 미리 알고 싶은데.","JPN":"将来世界を変える工学者の名前、今から覚えておきたいな。","ENG":"I would like to know the name of the engineer who will change the world.","TWN":"我想先知道可以改變未來世界工程師的名字。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NPC_GIRL","text":{"KOREA":"이졸데… 이졸데예요.","JPN":"イゾルデ……イゾルデです。","ENG":"Isolde... I'm Isolde.","TWN":"伊索德……我叫伊索德。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이졸데. 예쁜 이름이네.","JPN":"イゾルデ。素敵な名前ね。","ENG":"Isolde. That's a pretty name.","TWN":"伊索德，真是個好聽的名字。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"선로전환기라는 장치의 시스템 구축을 준비하고 있다고 들었다.","JPN":"線路転換器という装置のシステム構築を準備していると聞いた。","ENG":"I hear you are preparing to build the system for a device called the Track Switcher.","TWN":"聽說你正在準備建立線路轉換器這個裝置的系統。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"분명 혼자서는 무리인 작업일 터.","JPN":"きっと一人では無理な作業のはず。","ENG":"It is surely too much for one person.","TWN":"這肯定是無法單獨完成的工作。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"우리는 너에게 기술을 지원하겠다.","JPN":"私たちが技術支援をしよう。","ENG":"We will provide technical support.","TWN":"我們會給你技術支援。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"너희는 범죄자잖아. 우리가 너흴 어떻게 믿어?","JPN":"あなたたちは犯罪者でしょ。何を根拠に信用しろっていうの？","ENG":"You're criminals. How are we supposed to trust you?","TWN":"你們是罪犯，憑什麼要相信你們？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"믿지 않아도 상관없다.","JPN":"信用せずとも構わない。","ENG":"Your trust is irrelevant.","TWN":"不相信也無所謂。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너의 신뢰를 얻기 위한 행위에 들이는 시간은 무가치하니까.","JPN":"お前の信用を得るためにかける時間に価値はない。","ENG":"Time spent trying to earn it has no value.","TWN":"花時間去贏得你的信任毫無意義。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"공학자란 이론을 현실로 만드는 자.","JPN":"工学者は理論を現実にする者。","ENG":"An engineer turns theory into reality.","TWN":"工程師，是把理論化為現實的人。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자신의 이상을 실현할 기회가 왔음에도 이를 걷어차는 것은…….","JPN":"己の理想を実現するチャンスを自ら手放すのは……","ENG":"If you kick away a chance to realize your ideals...","TWN":"當有機會實現自己的理想卻放棄……."},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"결국 자신의 가치가 거기까지라는 것을 증명하는 셈일 테니.","JPN":"己の価値は所詮その程度だという証明に他ならない。","ENG":"You only prove that your worth extends no further.","TWN":"等於證明了自己的價值只到這裡而已。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그럼 이졸데, 이거 하나만 기억해 줄 수 있니?","JPN":"じゃあイゾルデ、これだけは覚えていてくれる？","ENG":"Isolde, could you remember this one thing for me?","TWN":"伊索德，妳能幫我記住一句話嗎？"},"stage":{"bg":"OMEN_LOTUS_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이 말을 간직하고 있다가, 꼭 세상을 지켜주길 바라.","JPN":"この言葉を忘れないで、世界を守ってね。","ENG":"Hold on to these words and use them to protect the world.","TWN":"希望妳能把它放在心裡，總有一天能守護世界。"},"stage":{"bg":"OMEN_LOTUS_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};